const rows = $input.all();
const profile = {};
for (const row of rows) {
  const key = row.json['Field Name (do not edit)'];
  const value = row.json['Your Value ✏️  Edit this column'];
  if (key !== undefined && key !== null && key !== '') {
    profile[String(key)] = value !== undefined && value !== null ? String(value) : '';
  }
}
return [{ json: profile }];

const profile = $input.first().json;
const profession = profile.profession || 'AI/ML software development';
const services = profile.primary_services || 'custom software, AI automation';

const searchQueries = [
  'custom software development',
  'AI ML development',
  'machine learning project',
  'computer vision project',
  'enterprise automation',
  'SaaS development',
  'workflow automation',
  'full stack development'
];

const keywordsSkip = [
  '[for hire]','for hire]','wordpress theme','shopify theme','logo design',
  'SEO services','social media management','content writing','virtual assistant',
  'data entry','graphic design','video editing','copywriting','i am available',
  'available for hire','seeking clients','my portfolio','i offer',
  'my services include','hire me','looking for work','seeking employment',
  'i will ','i am ready','hi client','with expertise in','i will design',
  'i will develop','i will build','i will create','i can help you',
  'my approach','i have experience','years of experience in','i specialize'
];

// UPWORK RSS sources
const upworkSources = searchQueries.map(q => ({
  platform: 'upwork',
  priority: 'critical',
  method: 'rss',
  url: `https://www.upwork.com/ab/feed/jobs/rss?q=${encodeURIComponent(q)}&sort=recency&paging=0%3B10`,
  query: q
}));

const freelancerSources = [
  { platform: 'freelancer', method: 'serpapi', query: 'site:freelancer.com/projects "enterprise" "AI" OR "automation" OR "SaaS"' },
  { platform: 'freelancer', method: 'serpapi', query: 'site:freelancer.com/projects "AI" "$10,000" OR "$20,000" OR "$50,000" OR "$100,000"' },
  { platform: 'freelancer', method: 'serpapi', query: 'site:freelancer.com/projects "build" "AI platform" OR "ML system" OR "computer vision system"' },
  { platform: 'freelancer', method: 'serpapi', query: 'site:freelancer.com/projects "AI development" OR "AI integration" "company" OR "business" OR "startup"' }
];

const guruSources = [
  { platform: 'guru', method: 'serpapi', query: 'site:guru.com/jobs "enterprise" OR "company" "AI" OR "automation" OR "machine learning"' },
  { platform: 'guru', method: 'serpapi', query: 'site:guru.com/jobs "AI integration" OR "AI development" OR "computer vision" OR "data pipeline"' },
  { platform: 'guru', method: 'serpapi', query: 'site:guru.com/jobs "build" "AI" OR "ML" OR "automation system" OR "SaaS platform"' },
  { platform: 'guru', method: 'serpapi', query: 'site:guru.com/jobs "Fixed Price" "AI" OR "machine learning" OR "computer vision" OR "data pipeline"' }
];

// PeoplePerHour removed - low signal, matches freelancer profiles not job content
const pphSources = [];

// CONTRA sources
const contraSources = [
  { platform: 'contra', priority: 'medium', method: 'scrape', url: 'https://contra.com/opportunities?category=engineering', query: 'engineering' },
  { platform: 'contra', priority: 'medium', method: 'scrape', url: 'https://contra.com/opportunities?category=software-development', query: 'software development' }
];

// TOPTAL source
const toptalSources = [
  { platform: 'toptal', priority: 'high', method: 'scrape', url: 'https://www.toptal.com/talent/apply', query: 'all projects' }
];

// FIVERR source
const fiverrSources = [
  { platform: 'fiverr', priority: 'low', method: 'scrape', url: 'https://www.fiverr.com/categories/programming-tech/software-development', query: 'software development' }
];

// CODEABLE source
const codeableSources = [
  { platform: 'codeable', priority: 'low', method: 'scrape', url: 'https://codeable.io/wordpress-developers/', query: 'wordpress development' }
];

return [{ json: {
  upworkSources,
  freelancerSources,
  guruSources,

  contraSources,
  toptalSources,
  fiverrSources,
  codeableSources,
  keywordsSkip,
  businessProfile: profile,
  searchQueries
}}];

// ============================================================
// EXTENDED SERP QUERIES — extra Guru + Freelancer angles
// Replaces broken Contra/Toptal/Fiverr/Codeable scrapers
// ============================================================
const config = $('Build Scrape Config').first().json;
const serpKey = $env.SERPAPI_KEY;

const extraQueries = [
  // Extra Guru angles
  { q: 'site:guru.com/jobs "AI agent" OR "AI chatbot" OR "LLM" OR "OpenAI" OR "AI workflow"', platform: 'guru' },
  { q: 'site:guru.com/jobs "python" "AI" OR "machine learning" OR "data pipeline" OR "automation"', platform: 'guru' },
  // Extra Freelancer angles
  { q: 'site:freelancer.com/projects "LLM" OR "GPT" OR "langchain" OR "AI agent" OR "RAG"', platform: 'freelancer' },
  { q: 'site:freelancer.com/projects "automation" "n8n" OR "make.com" OR "zapier" OR "workflow automation"', platform: 'freelancer' },
  // Truelancer - new source, good Google indexing
  { q: 'site:truelancer.com/freelance-project "AI" OR "machine learning" OR "automation" OR "LLM"', platform: 'truelancer' },
  { q: 'site:truelancer.com/freelance-project "AI agent" OR "AI development" OR "workflow automation" OR "n8n"', platform: 'truelancer' }
];

const withTimeout = (p, ms) => Promise.race([p, new Promise((_, r) => setTimeout(() => r(new Error('timeout')), ms))]);
const keywordsSkip = config.keywordsSkip || [];

const results = [];
const seen = new Set();

for (const qObj of extraQueries) {
  let resp;
  try {
    resp = await withTimeout(
      this.helpers.httpRequest({
        method: 'GET',
        url: 'https://serpapi.com/search.json',
        qs: { q: qObj.q, num: 10, api_key: serpKey, engine: 'google', gl: 'us', hl: 'en' }
      }),
      20000
    );
  } catch(e) { continue; }

  const organicResults = resp?.organic_results || [];
  for (const r of organicResults) {
    if (!r.link) continue;
    const platform = qObj.platform;
    // URL filter
    if (platform === 'freelancer' && !r.link.includes('freelancer.com/projects/')) continue;
    if (platform === 'guru'       && !r.link.includes('guru.com/jobs/'))           continue;
    if (platform === 'truelancer'  && !r.link.includes('truelancer.com/freelance-project/')) continue;

    const id = platform + '_' + Buffer.from(r.link).toString('base64').substring(0, 24);
    if (seen.has(id)) continue;
    seen.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (keywordsSkip.some(kw => fullText.includes(kw.toLowerCase()))) continue;

    const lowBudgetSignals = ['₹', 'rs.', 'inr', '$750-1500 usd', '$250-750 usd', '$150-300 usd', '$30-250 usd'];
    if (lowBudgetSignals.some(s => snippet.toLowerCase().includes(s))) continue;

    results.push({ json: {
      title,
      description: snippet,
      source: platform,
      source_url: r.link,
      source_id: id,
      posted_at: r.date ? new Date(r.date).toISOString() : new Date().toISOString(),
      author: '', subreddit: platform, upvotes: 0, num_comments: 0,
      flair_text: '', budget_text: '', platform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'extra-serp' } }];
return results;

// ============================================================
// NORMALIZE TO RawOpportunity - EXACT SAME FORMAT AS ORIGINAL
// ============================================================
const config = $('Build Scrape Config').first().json;
const keywordsSkip = config.keywordsSkip || [];
const rawItems = $input.all();
const results = [];
const seenInRun = new Set();

for (const item of rawItems) {
  if (!item.json || typeof item.json !== 'object') continue;
  const post = item.json;

  try {
    if (post._empty || post._noData) continue;
    const postTitle = String(post.title || '').substring(0, 500);
    if (!postTitle) continue;
    const postId = String(post.source_id || (post.platform + '_' + Buffer.from(postTitle).toString('base64').substring(0, 16)));
    if (seenInRun.has(postId)) continue;
    seenInRun.add(postId);
    const postBody = String(post.description || '');
    const fullText = (postTitle + ' ' + postBody).toLowerCase();
    if (keywordsSkip.some(kw => fullText.includes(kw.toLowerCase()))) continue;

    results.push({ json: {
      title: postTitle,
      description: postBody.substring(0, 3000),
      source: post.source || post.platform || 'unknown',
      source_url: post.source_url || '',
      source_id: postId,
      posted_at: post.posted_at || new Date().toISOString(),
      author: post.author || '',
      subreddit: post.platform || '',
      upvotes: post.upvotes || 0,
      num_comments: post.num_comments || 0,
      flair_text: post.flair_text || '',
      budget_text: post.budget_text || ''
    }});
  } catch(e) {
    console.error('[Normalize] Failed:', e.message);
  }
}

if (results.length === 0) return [];
return results;

const posts = $input.all().map(i => i.json).filter(p => p && p.title && !p._noData);
if (posts.length === 0) return [];

const apiKey = $env.GOOGLE_AI_API_KEY;
const BATCH_SIZE = 5;
const BETWEEN_BATCH_DELAY_MS = 1500;
const MAX_RETRIES = 2;
const CALL_TIMEOUT_MS = 120000;

const SYSTEM_PROMPT = `You are a senior business development analyst for ScaleBuild AI (CEO: Ujjwal Roy, ex-Intel/IBM/Micron), a custom AI/ML software development company.

ScaleBuild BUILDS: AI/ML models, computer vision, enterprise automation, custom software, data pipelines.

IDEAL LEAD: Founder/CTO/SMB owner with a business PROBLEM needing custom software. Pain point posts are HIGH VALUE.

HARD EXCLUSIONS — Score overall_score 0.0 immediately, do not process:
- Lead is from India or an Indian company (location: India, .in domain, Indian city/company name context) → 0.0
- Lead is requesting to build a SaaS subscription product (we do NOT build SaaS products) → 0.0  
- Budget is clearly under $10,000 OR budget_score would be below 0.3 → 0.0
- Individual freelancer or [For Hire] ad → 0.0

GOOD LEAD EXAMPLES:
- "compliance audits take weeks" → needs automation → HIGH
- "we outgrew our no-code tool" → needs custom dev → HIGH
- "evaluating dev shops" → MEDIUM
- "I built a meme AI" → 0.0
- Individual [For Hire] ad → 0.0

SCORE 4 DIMENSIONS (0.0-1.0):
1. relevance_score: 0.9+=clear AI/automation need | 0.7-0.8=business pain point | 0.5-0.6=startup needs tech help | 0.0-0.2=irrelevant
2. budget_score: 1.0=$50K+ | 0.8=$10-50K | 0.6=$5-10K | 0.4=$2-5K | 0.2=<$2K | 0.6=unknown but substantial scope described | 0.5=unknown budget no scope
3. urgency_score: 1.0=this week/ASAP | 0.8=within 1 month | 0.6=actively seeking proposals (open job post, quotes open) | 0.4=3-6 months | 0.2=passive/no timeline
4. win_probability: 0.9+=agency explicitly sought | 0.8=company/business posting with substantial budget ($5k+) | 0.6-0.7=company posting budget unclear | 0.4=unclear individual vs team | 0.2=explicitly wants solo freelancer | 0.0=no fit

COMPANY EXTRACTION:
- Scan title AND description for company name, product name, website URL
- Any URL becomes lead_website (domain only)
- No name found? Return null. Never invent names.
- lead_founder_name: use person name in post or username`;

const callGeminiWithRetry = async (prompt) => {
  const body = {
    contents: [{ parts: [{ text: prompt }] }],
    generationConfig: { maxOutputTokens: 10000, temperature: 0.2, responseMimeType: 'application/json' }
  };
  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      const result = await Promise.race([
        this.helpers.httpRequest({
          method: 'POST',
          url: 'https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash:generateContent?key=' + apiKey,
          body
        }),
        new Promise((_, reject) => setTimeout(() => reject(new Error('call_timeout')), CALL_TIMEOUT_MS))
      ]);
      return result;
    } catch(e) {
      const msg = String(e.message || '');
      if (msg === 'call_timeout') throw new Error('call_timeout');
      if (msg.includes('429') && attempt < MAX_RETRIES - 1) {
        await new Promise(r => setTimeout(r, Math.pow(2, attempt + 1) * 2000));
        continue;
      }
      throw e;
    }
  }
};

function computeScores(s) {
  const overall = Math.round((
    (s.relevance_score||0)*0.35 + (s.budget_score||0)*0.30 +
    (s.urgency_score||0)*0.15 + (s.win_probability||0)*0.20
  ) * 100) / 100;
  let alert_tier = 'discard';
  if (overall >= 0.85) alert_tier = 'instant';
  else if (overall >= 0.70) alert_tier = 'digest';
  else if (overall >= 0.30) alert_tier = 'dashboard';
  return { ...s, overall_score: overall, alert_tier };
}

function fallback(reason) {
  return computeScores({
    relevance_score:0.1, budget_score:0.1, urgency_score:0.1, win_probability:0.1,
    client_context: 'Could not extract client context',
    project_context: 'Could not extract project context',
    summary:'Parse error: '+reason, industry:'Unknown', tags:[], reasoning:reason,
    estimated_budget_text:null, deadline_text:null, location:null, tech_stack:[],
    company_name:null, contact_info:null, lead_founder_name:null, lead_website:null, reddit_author:null
  });
}

function buildItem(post, s) {
  return { json: {
    title: post.title,
    description: post.description,
    source: post.source,
    source_url: post.source_url,
    source_id: post.source_id,
    posted_at: post.posted_at,
    author: post.author,
    subreddit: post.subreddit,
    upvotes: post.upvotes,
    num_comments: post.num_comments,
    relevance_score: s.relevance_score,
    budget_score: s.budget_score,
    urgency_score: s.urgency_score,
    win_probability: s.win_probability,
    overall_score: s.overall_score,
    ai_summary: s.summary,
    client_context: s.client_context,
    project_context: s.project_context,
    industry: s.industry,
    ai_tags: s.tags || [],
    ai_reasoning: s.reasoning,
    estimated_budget_text: s.estimated_budget_text,
    deadline_text: s.deadline_text,
    location: s.location,
    tech_stack: s.tech_stack || [],
    company_name: s.company_name,
    contact_info: s.contact_info,
    lead_founder: s.lead_founder_name || post.lead_founder || null,
    lead_company: s.company_name || post.lead_company || null,
    lead_website: s.lead_website || post.lead_website || null,
    lead_contact: s.contact_info || null,
    lead_score: Math.round(s.overall_score * 10),
    alert_tier: s.alert_tier,
    discovered_at: new Date().toISOString(),
    status: 'new',
    outreach_draft: ''
  }};
}

const results = [];
for (let i = 0; i < posts.length; i += BATCH_SIZE) {
  const batch = posts.slice(i, i + BATCH_SIZE);
  const postsBlock = batch.map((p, idx) =>
    'POST ' + (idx+1) + ':\nTitle: ' + p.title +
    '\nSource: ' + (p.source||'') +
    '\nAuthor: ' + (p.author||'unknown') +
    '\nDescription: ' + (p.description||'').substring(0, 600)
  ).join('\n\n---\n\n');

  const schema = '{"relevance_score":0.0,"budget_score":0.0,"urgency_score":0.0,"win_probability":0.0,"client_context":"Detailed description of who the client is","project_context":"Detailed description of what they want built","summary":"1-2 sentences","industry":"FinTech/HealthTech/SaaS/Manufacturing/eCommerce/General","tags":[],"reasoning":"brief","estimated_budget_text":null,"deadline_text":null,"location":null,"tech_stack":[],"company_name":null,"contact_info":null,"lead_founder_name":null,"lead_website":null,"reddit_author":null}';
  const prompt = SYSTEM_PROMPT + '\n\nScore ALL ' + batch.length + ' posts. Return ONLY a valid JSON array with exactly ' + batch.length + ' objects. Each object must have: ' + schema + '\n\n' + postsBlock;

  let batchScores = null;
  let debugSnippet = '';
  try {
    const respRaw = await callGeminiWithRetry(prompt);
    const resp = typeof respRaw === 'string' ? JSON.parse(respRaw) : respRaw;
    const raw = resp?.candidates?.[0]?.content?.parts?.[0]?.text || '';
    debugSnippet = raw.substring(0, 300);
    const cleaned = raw.replace(/```json[\s\S]*?```|```/g, '').trim();
    const match = cleaned.match(/\[[\s\S]*\]/);
    if (match) {
      const parsed = JSON.parse(match[0]);
      if (Array.isArray(parsed) && parsed.length > 0) batchScores = parsed;
    }
  } catch(e) { debugSnippet = 'EXCEPTION: ' + e.message; }

  for (let j = 0; j < batch.length; j++) {
    const s = batchScores && batchScores[j] ? computeScores(batchScores[j]) : fallback(debugSnippet || 'no response');
    results.push(buildItem(batch[j], s));
  }

  if (i + BATCH_SIZE < posts.length) await new Promise(r => setTimeout(r, BETWEEN_BATCH_DELAY_MS));
}

return results;

const hunterResp = $input.item.json;
const original = $('Check - Has Lead Info').item.json;
const data = hunterResp?.data || {};
const emails = data.emails || [];
const priority = ['ceo','founder','co-founder','cto','owner','president','vp','director'];
let person = emails.find(e => priority.some(t => (e.position||'').toLowerCase().includes(t))) || emails[0] || null;
return [{ json: {
  ...original,
  hunter_name: person ? `${person.first_name||''} ${person.last_name||''}`.trim() : '',
  hunter_email: person?.value || '',
  hunter_title: person?.position || '',
  hunter_company: data.organization || original.lead_company || ''
}}];

return [{ json: {
  ...$input.item.json,
  hunter_name: '',
  hunter_email: '',
  hunter_title: '',
  hunter_company: ''
}}];

const seen = new Map();
for (const item of $input.all()) {
  const id = item.json.source_id;
  if (!id) continue;
  if (!seen.has(id)) {
    seen.set(id, item.json);
  } else {
    if (item.json.hunter_email && !seen.get(id).hunter_email) {
      seen.set(id, item.json);
    }
  }
}
return [...seen.values()]
  .sort((a, b) => (b.overall_score||0) - (a.overall_score||0))
  .map(json => ({ json }));

const config = $('Build Scrape Config').first().json;
const queries = [];

// Freelancer queries (SerpAPI)
const flSources = config.freelancerSources || [];
for (const s of flSources) {
  queries.push({ json: { q: s.query, platform: 'freelancer' } });
}

// Guru queries (SerpAPI)
const guruSources = config.guruSources || [];
for (const s of guruSources) {
  queries.push({ json: { q: s.query, platform: 'guru' } });
}

return queries;

const config = $('Build Scrape Config').first().json;
const keywordsSkip = config.keywordsSkip || [];
const results = [];
const seenInRun = new Set();

for (const item of $input.all()) {
  const data = item.json;
  if (!data || data.error) continue;

  const organicResults = data.organic_results || [];
  const searchQ = data.search_parameters?.q || '';

  // Determine platform from query
  let platform = 'unknown';
  if (searchQ.includes('freelancer.com')) platform = 'freelancer';
  else if (searchQ.includes('guru.com')) platform = 'guru';
  else if (searchQ.includes('peopleperhour.com')) platform = 'peopleperhour';

  for (const r of organicResults) {
    if (!r.link) continue;

    // Filter by correct URL patterns
    if (platform === 'freelancer' && !r.link.includes('freelancer.com/projects/')) continue;
    if (platform === 'guru' && !r.link.includes('guru.com/jobs/')) continue;
    if (platform === 'unknown') continue;

    const id = platform + '_' + Buffer.from(r.link).toString('base64').substring(0, 24);
    if (seenInRun.has(id)) continue;
    seenInRun.add(id);

    const title   = String(r.title   || '').substring(0, 500);
    const snippet = String(r.snippet || '').replace(/<[^>]*>/g, '').substring(0, 3000);
    if (!title) continue;

    const fullText = (title + ' ' + snippet).toLowerCase();
    if (keywordsSkip.some(kw => fullText.includes(kw.toLowerCase()))) continue;

    // Skip clearly low-budget results (small gigs, INR rates, hourly under $50)
    // Only block if the TITLE itself has low budget - snippets have noise
    const titleLower = title.toLowerCase();
    const lowBudgetSignals = ['₹', 'rs.', 'inr', '$750-1500 usd', '$250-750 usd', '$150-300 usd', '$30-250 usd', '$8-15/hr', '$10-20/hr'];
    if (lowBudgetSignals.some(s => titleLower.includes(s) || snippet.toLowerCase().includes(s))) continue;

    results.push({ json: {
      title,
      description: snippet,
      source: platform,
      source_url: r.link,
      source_id: id,
      posted_at: (() => { try { const d = r.date ? new Date(r.date) : null; return (d && !isNaN(d)) ? d.toISOString() : new Date().toISOString(); } catch(e) { return new Date().toISOString(); } })(),
      author: '',
      subreddit: '',
      upvotes: 0,
      num_comments: 0,
      flair_text: '',
      budget_text: '',
      platform
    }});
  }
}

if (results.length === 0) return [{ json: { _empty: true, platform: 'marketplace' } }];
return results;

// Pass-through — extract budget from SerpAPI snippet directly
// Guru page fetch removed (blocking/timeout). SerpAPI snippet already has budget.
const results = [];

for (const item of $input.all()) {
  const post = { ...item.json };
  if (post._empty || post._noData) { results.push({ json: post }); continue; }

  // If description already has budget signal from SerpAPI snippet, boost it
  const desc = post.description || '';
  const budgetMatch = desc.match(/(Fixed Price|Hourly)[^|\n]*\|[^$\n]*\$[\d,k\-\.]+/i)
    || desc.match(/\$(\d[\d,\.]+k?)[\s\-–]+\$(\d[\d,\.]+k?)/i)
    || desc.match(/\$([\d,\.]+)(?:k|K|,000)/);

  if (budgetMatch && !post.budget_text) {
    post.budget_text = budgetMatch[0].trim();
  }

  results.push({ json: post });
}

return results;
